// export default LoginModal;

import React, { useState, useEffect } from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';

const LoginModal = ({ isOpen, onClose, onRegisterClick }) => {
    const { t } = useTranslation();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [rememberMe, setRememberMe] = useState(false);
    const [isVisible, setIsVisible] = useState(false);
    const [isLoading, setIsLoading] = useState(false);
    const [formError, setFormError] = useState('');
    const [showPassword, setShowPassword] = useState(false);
    const [showForgotPassword, setShowForgotPassword] = useState(false);
    const [forgotEmail, setForgotEmail] = useState('');
    const [forgotLoading, setForgotLoading] = useState(false);
    const [forgotMessage, setForgotMessage] = useState('');
    const [forgotError, setForgotError] = useState('');
    const history = useHistory();

    const API_BASE_URL = process.env.REACT_APP_API_URL;

    useEffect(() => {
        if (isOpen) {
            document.body.style.overflow = 'hidden';
            requestAnimationFrame(() => {
                setIsVisible(true);
            });
        } else {
            setIsVisible(false);
            document.body.style.overflow = 'auto';
        }
        
        return () => {
            document.body.style.overflow = 'auto';
        };
    }, [isOpen]);

    // Close modal on escape key
    useEffect(() => {
        const handleEsc = (event) => {
            if (event.keyCode === 27) onClose();
        };
        window.addEventListener('keydown', handleEsc);
        
        return () => {
            window.removeEventListener('keydown', handleEsc);
        };
    }, [onClose]);

    // Initialize animated background elements
    useEffect(() => {
        if (isVisible) {
            const createAnimatedElements = () => {
                const overlay = document.querySelector('.login-modal-overlay');
                if (!overlay) return;
                
                // Clear existing elements
                const existingElements = overlay.querySelectorAll('.animated-element');
                existingElements.forEach(el => el.remove());
                
                // Create floating shapes
                const shapes = ['circle', 'hexagon', 'triangle'];
                const count = window.innerWidth > 768 ? 8 : 5;
                
                for (let i = 0; i < count; i++) {
                    const element = document.createElement('div');
                    element.className = `animated-element ${shapes[i % shapes.length]}`;
                    
                    const size = Math.random() * 60 + 30;
                    const posX = Math.random() * 100;
                    const posY = Math.random() * 100;
                    const duration = Math.random() * 15 + 10;
                    const delay = Math.random() * 3;
                    
                    element.style.cssText = `
                        position: absolute;
                        width: ${size}px;
                        height: ${size}px;
                        left: ${posX}%;
                        top: ${posY}%;
                        background: linear-gradient(45deg, rgba(59, 130, 246, 0.08), rgba(147, 51, 234, 0.08));
                        border-radius: ${shapes[i % shapes.length] === 'circle' ? '50%' : '20%'};
                        animation: float ${duration}s ease-in-out ${delay}s infinite;
                        z-index: 1;
                        backdrop-filter: blur(10px);
                    `;
                    
                    overlay.appendChild(element);
                }
            };
            
            createAnimatedElements();
            window.addEventListener('resize', createAnimatedElements);
            
            return () => {
                window.removeEventListener('resize', createAnimatedElements);
            };
        }
    }, [isVisible]);

    const handleForgotPassword = async (e) => {
        e.preventDefault();
        setForgotError('');
        setForgotMessage('');
        setForgotLoading(true);
    
        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/forgot-password`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ email: forgotEmail })
            });
    
            const data = await response.json();
    
            if (!response.ok) {
                throw new Error(data.message || 'Failed to send reset email');
            }
    
            setForgotMessage('OTP sent successfully! Redirecting...');
            
            setTimeout(() => {
                history.push('/verify-otp', { 
                    email: forgotEmail 
                });
                onClose();
            }, 1500);
    
        } catch (error) {
            console.error('Forgot password error:', error);
            setForgotError(error.message || 'Service temporarily unavailable. Please contact support.');
        } finally {
            setForgotLoading(false);
        }
    };

    const handleLogin = async (e) => {
        e.preventDefault();
        setFormError('');
        setIsLoading(true);
        
        try {
            const response = await fetch(`${API_BASE_URL}/api/auth/login`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    email,
                    password
                })
            });

            const contentType = response.headers.get('content-type');
            if (!contentType || !contentType.includes('application/json')) {
                throw new Error('Server returned non-JSON response. Check if the API endpoint exists.');
            }

            const data = await response.json();
            
            if (!response.ok) {
                throw new Error(data.message || t('login.errors.loginFailed'));
            }
            
            localStorage.setItem('authToken', data.token);
            localStorage.setItem('userRole', data.role || data.user?.role);
            localStorage.setItem('userEmail', data.user?.email || email);
            localStorage.setItem('userName', `${data.user?.firstName || ''} ${data.user?.lastName || ''}`.trim());
            localStorage.setItem('userId', data.user?.id);
            
            onClose();
            history.push('/dashboard');
            
        } catch (error) {
            console.error('Login error:', error);
            
            let errorMessage = t('login.errors.invalidCredentials');
            
            if (error.message.includes('non-JSON response')) {
                errorMessage = 'Server error. Please check if the backend is running properly.';
            } else if (error.message.includes('Failed to fetch')) {
                errorMessage = 'Cannot connect to server. Please check your internet connection.';
            } else if (error.message) {
                errorMessage = error.message;
            }
            
            setFormError(errorMessage);
        } finally {
            setIsLoading(false);
        }
    };

    // Clear form when modal closes
    useEffect(() => {
        if (!isOpen) {
            setEmail('');
            setPassword('');
            setFormError('');
            setShowForgotPassword(false);
            setForgotEmail('');
            setForgotError('');
            setForgotMessage('');
        }
    }, [isOpen]);

    return (
        <>
            {/* Modal Overlay */}
            <div 
                className={`login-modal-overlay fixed inset-0 z-50 flex items-center justify-center p-3 sm:p-4 md:p-6 transition-all duration-700 ${
                    isOpen ? 'opacity-100 visible' : 'opacity-0 invisible'
                } ${isVisible ? 'backdrop-blur-2xl bg-gradient-to-br from-slate-900/20 via-blue-900/20 to-purple-900/20' : 'backdrop-blur-none bg-black/0'}`}
                onClick={onClose}
            >
                {/* Modal Container */}
                <div 
                    className={`relative w-full max-w-sm sm:max-w-md lg:max-w-lg transform transition-all duration-700 ${
                        isVisible ? 'scale-100 translate-y-0 opacity-100' : 'scale-90 translate-y-12 opacity-0'
                    }`}
                    onClick={e => e.stopPropagation()}
                >
                    {/* Glass Effect Background */}
                    <div className="absolute inset-0 bg-gradient-to-br from-white/25 via-white/15 to-white/5 backdrop-blur-3xl rounded-3xl sm:rounded-4xl border border-white/40 shadow-2xl"></div>
                    
                    {/* Close Button */}
                    <button 
                        className="absolute -top-3 -right-3 sm:-top-4 sm:-right-4 z-20 w-8 h-8 sm:w-10 sm:h-10 bg-white/95 hover:bg-white rounded-full shadow-xl flex items-center justify-center transition-all duration-300 hover:scale-110 group border border-white/50"
                        onClick={onClose} 
                        aria-label={t('login.closeModal')}
                    >
                        <span className="material-icons text-sm sm:text-base text-slate-600 group-hover:text-slate-800 transition-colors">close</span>
                    </button>
                    
                    {/* Modal Content */}
                    <div className="relative z-10 p-4 sm:p-6 lg:p-8">
                        {!showForgotPassword ? (
                            <>
                                {/* Header with Enhanced Rings (Same as Preloader) */}
                                <div className="text-center mb-6 sm:mb-8">
                                    {/* Ring Animation Container - Responsive Sizes */}
                                    <div className="relative w-28 h-28 sm:w-36 sm:h-36 lg:w-44 lg:h-44 mx-auto mb-4 sm:mb-6">
                                        <div className="absolute inset-0" style={{ perspective: '800px' }}>
                                            {/* Ring 1 - Pink */}
                                            <div 
                                                className="absolute inset-0 border border-transparent rounded-full ring-1"
                                                style={{
                                                    borderBottom: '6px solid rgb(255, 141, 249)',
                                                    animation: 'rotate1 2s linear infinite'
                                                }}
                                            ></div>
                                            
                                            {/* Ring 2 - Red */}
                                            <div 
                                                className="absolute inset-1 sm:inset-2 border border-transparent rounded-full ring-2"
                                                style={{
                                                    borderBottom: '6px solid rgb(255, 65, 106)',
                                                    animation: 'rotate2 2s linear infinite'
                                                }}
                                            ></div>
                                            
                                            {/* Ring 3 - Cyan */}
                                            <div 
                                                className="absolute inset-2 sm:inset-4 border border-transparent rounded-full ring-3"
                                                style={{
                                                    borderBottom: '6px solid rgb(0, 255, 255)',
                                                    animation: 'rotate3 2s linear infinite'
                                                }}
                                            ></div>
                                            
                                            {/* Ring 4 - Yellow */}
                                            <div 
                                                className="absolute inset-3 sm:inset-6 border border-transparent rounded-full ring-4"
                                                style={{
                                                    borderBottom: '6px solid rgb(252, 183, 55)',
                                                    animation: 'rotate4 2s linear infinite'
                                                }}
                                            ></div>
                                        </div>
                                        
                                        {/* Center Logo Text */}
                                        <div className="absolute inset-0 flex items-center justify-center">
                                            <div className="text-center leading-none">
                                                <div className="text-xs sm:text-sm lg:text-base font-black text-transparent bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 bg-clip-text">
                                                    FORUM<br/>ACADEMY
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    
                                    <h2 className="text-xl sm:text-2xl lg:text-3xl font-bold text-slate-800 mb-2">{t('login.header.title')}</h2>
                                    <p className="text-sm sm:text-base text-slate-600 px-2">{t('login.header.subtitle')}</p>
                                </div>
                                
                                {/* Error Message */}
                                {formError && (
                                    <div className="mb-4 sm:mb-6 p-3 sm:p-4 bg-red-50/80 backdrop-blur-sm border border-red-200/60 rounded-xl sm:rounded-2xl flex items-center space-x-3 animate-shake">
                                        <span className="material-icons text-red-500 text-lg sm:text-xl">error_outline</span>
                                        <span className="text-red-700 text-xs sm:text-sm font-medium">{formError}</span>
                                    </div>
                                )}
                                
                                {/* Login Form */}
                                <form onSubmit={handleLogin} className="space-y-4 sm:space-y-5">
                                    {/* Email Input */}
                                    <div className="group">
                                        <div className="relative">
                                            <div className="absolute inset-y-0 left-0 pl-3 sm:pl-4 flex items-center pointer-events-none">
                                                <span className="material-icons text-slate-400 group-focus-within:text-blue-500 transition-colors text-lg sm:text-xl">email</span>
                                            </div>
                                            <input
                                                type="email"
                                                placeholder={t('login.form.emailPlaceholder')}
                                                value={email}
                                                onChange={(e) => setEmail(e.target.value)}
                                                required
                                                className="w-full pl-10 sm:pl-12 pr-3 sm:pr-4 py-3 sm:py-4 bg-white/80 backdrop-blur-sm border border-slate-200/60 rounded-xl sm:rounded-2xl focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all duration-300 text-slate-800 placeholder-slate-400 text-sm sm:text-base"
                                            />
                                        </div>
                                    </div>
                                    
                                    {/* Password Input */}
                                    <div className="group">
                                        <div className="relative">
                                            <div className="absolute inset-y-0 left-0 pl-3 sm:pl-4 flex items-center pointer-events-none">
                                                <span className="material-icons text-slate-400 group-focus-within:text-blue-500 transition-colors text-lg sm:text-xl">lock</span>
                                            </div>
                                            <input
                                                type={showPassword ? "text" : "password"}
                                                placeholder={t('login.form.passwordPlaceholder')}
                                                value={password}
                                                onChange={(e) => setPassword(e.target.value)}
                                                required
                                                className="w-full pl-10 sm:pl-12 pr-10 sm:pr-12 py-3 sm:py-4 bg-white/80 backdrop-blur-sm border border-slate-200/60 rounded-xl sm:rounded-2xl focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all duration-300 text-slate-800 placeholder-slate-400 text-sm sm:text-base"
                                            />
                                            <button
                                                type="button"
                                                onClick={() => setShowPassword(!showPassword)}
                                                className="absolute inset-y-0 right-0 pr-3 sm:pr-4 flex items-center text-slate-400 hover:text-slate-600 transition-colors"
                                            >
                                                <span className="material-icons text-lg sm:text-xl">
                                                    {showPassword ? 'visibility_off' : 'visibility'}
                                                </span>
                                            </button>
                                        </div>
                                    </div>
                                    
                                    {/* Form Options */}
                                    <div className="flex items-center justify-between text-sm">
                                        <label className="flex items-center space-x-2 sm:space-x-3 cursor-pointer group">
                                            <div className="relative">
                                                <input
                                                    type="checkbox"
                                                    checked={rememberMe}
                                                    onChange={() => setRememberMe(!rememberMe)}
                                                    className="sr-only"
                                                />
                                                <div className={`w-4 h-4 sm:w-5 sm:h-5 rounded border-2 transition-all duration-300 ${
                                                    rememberMe 
                                                        ? 'bg-blue-500 border-blue-500' 
                                                        : 'bg-white/80 border-slate-300 group-hover:border-blue-300'
                                                }`}>
                                                    {rememberMe && (
                                                        <span className="material-icons text-white text-xs sm:text-sm absolute inset-0 flex items-center justify-center">check</span>
                                                    )}
                                                </div>
                                            </div>
                                            <span className="text-xs sm:text-sm text-slate-600 group-hover:text-slate-800 transition-colors">
                                                {t('login.form.rememberMe')}
                                            </span>
                                        </label>
                                        
                                        <button
                                            type="button"
                                            onClick={() => setShowForgotPassword(true)}
                                            className="text-xs sm:text-sm text-blue-600 hover:text-blue-700 font-medium transition-colors"
                                        >
                                            {t('login.form.forgotPassword')}
                                        </button>
                                    </div>
                                    
                                    {/* Login Button */}
                                    <button 
                                        type="submit" 
                                        disabled={isLoading}
                                        className="w-full py-3 sm:py-4 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white font-semibold rounded-xl sm:rounded-2xl shadow-lg hover:shadow-xl transform hover:scale-[1.02] transition-all duration-300 flex items-center justify-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none text-sm sm:text-base"
                                    >
                                        {isLoading ? (
                                            <>
                                                <div className="w-4 h-4 sm:w-5 sm:h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                                <span>{t('login.form.signingIn')}</span>
                                            </>
                                        ) : (
                                            <>
                                                <span>{t('login.form.signIn')}</span>
                                                <span className="material-icons text-lg sm:text-xl">arrow_forward</span>
                                            </>
                                        )}
                                    </button>
                                    
                                    {/* Register Section */}
                                    <div className="pt-4 sm:pt-6">
                                        <div className="relative">
                                            <div className="absolute inset-0 flex items-center">
                                                <div className="w-full border-t border-slate-200/60"></div>
                                            </div>
                                            <div className="relative flex justify-center text-xs sm:text-sm">
                                                <span className="px-3 sm:px-4 bg-white/80 backdrop-blur-sm text-slate-500">
                                                    {t('login.register.newToPlatform')}
                                                </span>
                                            </div>
                                        </div>
                                        
                                        <button
                                            type="button"
                                            onClick={onRegisterClick}
                                            className="w-full mt-3 sm:mt-4 py-3 sm:py-4 bg-white/90 hover:bg-white backdrop-blur-sm border border-slate-200/60 hover:border-slate-300 text-slate-700 font-semibold rounded-xl sm:rounded-2xl shadow-sm hover:shadow-md transform hover:scale-[1.02] transition-all duration-300 flex items-center justify-center space-x-2 text-sm sm:text-base"
                                        >
                                            <span className="material-icons text-lg sm:text-xl">person_add</span>
                                            <span>{t('login.register.createAccount')}</span>
                                        </button>
                                    </div>
                                </form>
                            </>
                        ) : (
                            /* Forgot Password Form */
                            <>
                                {/* Header with Enhanced Rings */}
                                <div className="text-center mb-6 sm:mb-8">
                                    <div className="relative w-28 h-28 sm:w-36 sm:h-36 lg:w-44 lg:h-44 mx-auto mb-4 sm:mb-6">
                                        <div className="absolute inset-0" style={{ perspective: '800px' }}>
                                            <div 
                                                className="absolute inset-0 border border-transparent rounded-full"
                                                style={{
                                                    borderBottom: '6px solid rgb(255, 141, 249)',
                                                    animation: 'rotate1 2s linear infinite'
                                                }}
                                            ></div>
                                            <div 
                                                className="absolute inset-1 sm:inset-2 border border-transparent rounded-full"
                                                style={{
                                                    borderBottom: '6px solid rgb(255, 65, 106)',
                                                    animation: 'rotate2 2s linear infinite'
                                                }}
                                            ></div>
                                            <div 
                                                className="absolute inset-2 sm:inset-4 border border-transparent rounded-full"
                                                style={{
                                                    borderBottom: '6px solid rgb(0, 255, 255)',
                                                    animation: 'rotate3 2s linear infinite'
                                                }}
                                            ></div>
                                            <div 
                                                className="absolute inset-3 sm:inset-6 border border-transparent rounded-full"
                                                style={{
                                                    borderBottom: '6px solid rgb(252, 183, 55)',
                                                    animation: 'rotate4 2s linear infinite'
                                                }}
                                            ></div>
                                        </div>
                                        <div className="absolute inset-0 flex items-center justify-center">
                                            <div className="text-center leading-none">
                                                <div className="text-xs sm:text-sm lg:text-base font-black text-transparent bg-gradient-to-r from-blue-600 via-purple-600 to-pink-600 bg-clip-text">
                                                    FORUM<br/>ACADEMY
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                    
                                    <h2 className="text-xl sm:text-2xl lg:text-3xl font-bold text-slate-800 mb-2">Reset Password</h2>
                                    <p className="text-sm sm:text-base text-slate-600 px-2">Enter your email address and we'll send you a link to reset your password.</p>
                                </div>

                                {/* Messages */}
                                {forgotError && (
                                    <div className="mb-4 sm:mb-6 p-3 sm:p-4 bg-red-50/80 backdrop-blur-sm border border-red-200/60 rounded-xl sm:rounded-2xl flex items-center space-x-3 animate-shake">
                                        <span className="material-icons text-red-500 text-lg sm:text-xl">error_outline</span>
                                        <span className="text-red-700 text-xs sm:text-sm font-medium">{forgotError}</span>
                                    </div>
                                )}

                                {forgotMessage && (
                                    <div className="mb-4 sm:mb-6 p-3 sm:p-4 bg-green-50/80 backdrop-blur-sm border border-green-200/60 rounded-xl sm:rounded-2xl flex items-center space-x-3 animate-bounce">
                                        <span className="material-icons text-green-500 text-lg sm:text-xl">check_circle</span>
                                        <span className="text-green-700 text-xs sm:text-sm font-medium">{forgotMessage}</span>
                                    </div>
                                )}

                                {/* Forgot Password Form */}
                                <form onSubmit={handleForgotPassword} className="space-y-4 sm:space-y-6">
                                    <div className="group">
                                        <div className="relative">
                                            <div className="absolute inset-y-0 left-0 pl-3 sm:pl-4 flex items-center pointer-events-none">
                                                <span className="material-icons text-slate-400 group-focus-within:text-blue-500 transition-colors text-lg sm:text-xl">email</span>
                                            </div>
                                            <input
                                                type="email"
                                                placeholder="Enter your email address"
                                                value={forgotEmail}
                                                onChange={(e) => setForgotEmail(e.target.value)}
                                                required
                                                className="w-full pl-10 sm:pl-12 pr-3 sm:pr-4 py-3 sm:py-4 bg-white/80 backdrop-blur-sm border border-slate-200/60 rounded-xl sm:rounded-2xl focus:ring-4 focus:ring-blue-500/20 focus:border-blue-500 outline-none transition-all duration-300 text-slate-800 placeholder-slate-400 text-sm sm:text-base"
                                            />
                                        </div>
                                    </div>

                                    <button 
                                        type="submit" 
                                        disabled={forgotLoading}
                                        className="w-full py-3 sm:py-4 bg-gradient-to-r from-blue-600 to-purple-600 hover:from-blue-700 hover:to-purple-700 text-white font-semibold rounded-xl sm:rounded-2xl shadow-lg hover:shadow-xl transform hover:scale-[1.02] transition-all duration-300 flex items-center justify-center space-x-2 disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none text-sm sm:text-base"
                                    >
                                        {forgotLoading ? (
                                            <>
                                                <div className="w-4 h-4 sm:w-5 sm:h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                                                <span>Sending...</span>
                                            </>
                                        ) : (
                                            <>
                                                <span>Send Reset Email</span>
                                                <span className="material-icons text-lg sm:text-xl">send</span>
                                            </>
                                        )}
                                    </button>

                                    <button
                                        type="button"
                                        onClick={() => setShowForgotPassword(false)}
                                        className="w-full py-2 sm:py-3 text-slate-600 hover:text-slate-800 font-medium transition-colors flex items-center justify-center space-x-2 text-sm sm:text-base"
                                    >
                                        <span className="material-icons text-lg sm:text-xl">arrow_back</span>
                                        <span>Back to Login</span>
                                    </button>
                                </form>
                            </>
                        )}
                    </div>
                </div>
            </div>

            {/* Custom Animations - Enhanced from Preloader */}
            <style>{`
                @keyframes rotate1 {
                    from { transform: rotateX(50deg) rotateZ(110deg); }
                    to { transform: rotateX(50deg) rotateZ(470deg); }
                }

                @keyframes rotate2 {
                    from { transform: rotateX(20deg) rotateY(50deg) rotateZ(20deg); }
                    to { transform: rotateX(20deg) rotateY(50deg) rotateZ(380deg); }
                }

                @keyframes rotate3 {
                    from { transform: rotateX(40deg) rotateY(130deg) rotateZ(450deg); }
                    to { transform: rotateX(40deg) rotateY(130deg) rotateZ(90deg); }
                }

                @keyframes rotate4 {
                    from { transform: rotateX(70deg) rotateZ(270deg); }
                    to { transform: rotateX(70deg) rotateZ(630deg); }
                }
                
                @keyframes float {
                    0%, 100% { transform: translateY(0px) rotate(0deg); }
                    33% { transform: translateY(-8px) rotate(120deg); }
                    66% { transform: translateY(4px) rotate(240deg); }
                }
                
                @keyframes shake {
                    0%, 100% { transform: translateX(0); }
                    25% { transform: translateX(-3px); }
                    75% { transform: translateX(3px); }
                }
                
                .animate-shake {
                    animation: shake 0.5s ease-in-out;
                }
                
                @media (max-width: 640px) {
                    .ring-1, .ring-2, .ring-3, .ring-4 {
                        border-bottom-width: 4px !important;
                    }
                }
            `}</style>
        </>
    );
};

export default LoginModal;
